const { execSync, spawn } = require('child_process');
const { writeFileSync, mkdirSync, existsSync, openSync } = require('fs');
const body = $input.first().json.body || $input.first().json;
const { taskId, repo, branch, goal, tier, skills, declaredFiles, constraints, role, callbackUrl } = body;
if (!taskId || !repo || !goal) return [{ json: { error: 'Missing fields' } }];
const WORKSPACES = '/workspaces/smo';
const LOG_DIR = '/root/.smo/logs';
mkdirSync(LOG_DIR, { recursive: true });
const repoName = repo.split('/').pop();
const repoDir = WORKSPACES + '/' + repoName;
if (!existsSync(repoDir)) {
  try { execSync('git clone git@github.com:' + repo + '.git ' + repoDir, { timeout: 120000 }); }
  catch(e) { return [{ json: { taskId, status: 'error', error: e.message.slice(0,200) } }]; }
}
try {
  execSync('cd ' + repoDir + ' && git fetch origin && (git checkout -b ' + branch + ' origin/main 2>/dev/null || git checkout ' + branch + ')', { timeout: 30000 });
} catch(e) { return [{ json: { taskId, status: 'error', error: e.message.slice(0,200) } }]; }
const effectiveTier = tier || 'staged_hybrid';
let script = '#!/bin/bash\nset -euo pipefail\ncd ' + repoDir + '\n';
const sq = (s) => s.replace(/'/g, "'\\''" );
if (effectiveTier === 'fast_track') {
  script += "codex --auto-edit --message '" + sq(goal) + "' --timeout 1800 --approval-mode auto-edit\n";
} else if (effectiveTier === 'staged_hybrid') {
  script += "claude -p 'Plan: " + sq(goal) + ". Output JSON spec.' --output-file /tmp/SPEC-" + taskId + ".json\n";
  script += 'SPEC=$(cat /tmp/SPEC-' + taskId + '.json)\n';
  script += 'codex --auto-edit --message "Execute: $SPEC" --timeout 3600\n';
} else {
  script += "claude -p 'You are " + (role || 'engineer') + ". " + (skills ? 'Skills: ' + skills + '. ' : '') + 'Task: ' + sq(goal) + "' --max-turns 50\n";
}
script += '\ngit add -A\ngit commit -m "agent(' + taskId + '): auto" --allow-empty || true\ngit push origin ' + branch + ' 2>/dev/null || git push --set-upstream origin ' + branch + '\n';
if (callbackUrl) {
  script += '\ncurl -s -X POST ' + callbackUrl + ' -H "Content-Type: application/json" -d \'{"taskId":"' + taskId + '","exitCode":0}\' || true\n';
}
const scriptPath = '/tmp/exec-' + taskId + '.sh';
writeFileSync(scriptPath, script);
execSync('chmod +x ' + scriptPath);
const out = openSync(LOG_DIR + '/' + taskId + '.log', 'a');
const child = spawn('bash', [scriptPath], { detached: true, stdio: ['ignore', out, out] });
child.unref();
return [{ json: { taskId, status: 'executing', pid: child.pid, tier: effectiveTier } }];
